import { ApplicationConfig }    from '@angular/core';
import { provideRouter }        from '@angular/router';
import {
  provideHttpClient,
  withInterceptors,            // for functional interceptors
  withFetch,                   // use fetch API instead of XHR (optional)
} from '@angular/common/http';
import { routes }              from './app.routes';
import { authInterceptor }     from './core/interceptors/auth.interceptor';
import { loggingInterceptor }  from './core/interceptors/logging.interceptor';

export const appConfig: ApplicationConfig = {
  providers: [
    provideRouter(routes),

    // Register HttpClient once here — inject anywhere in the app
    provideHttpClient(
      withInterceptors([authInterceptor, loggingInterceptor]),
      withFetch(),   // optional: use fetch instead of XMLHttpRequest
    ),
  ],
};

import { Injectable, inject, signal, computed } from '@angular/core';
import { HttpClient, HttpParams } from '@angular/common/http';
import { catchError, EMPTY, tap } from 'rxjs';

export interface Post {
  id:     number;
  title:  string;
  body:   string;
  userId: number;
}

@Injectable({ providedIn: 'root' })
export class PostsService {
  private http = inject(HttpClient);
  private BASE  = 'https://jsonplaceholder.typicode.com';

  // ── Reactive state signals ─────────────────────────────────
  private _posts   = signal<Post[]>([]);
  private _loading = signal(false);
  private _error   = signal<string | null>(null);

  readonly posts   = this._posts.asReadonly();
  readonly loading = this._loading.asReadonly();
  readonly error   = this._error.asReadonly();
  readonly count   = computed(() => this._posts().length);

  // ── GET all posts ──────────────────────────────────────────
  loadPosts(): void {
    this._loading.set(true);
    this._error.set(null);

    this.http
      .get<Post[]>(`${this.BASE}/posts`)
      .pipe(
        catchError(err => {
          this._error.set(err.message);
          this._loading.set(false);
          return EMPTY;          // stop the stream, don't propagate
        })
      )
      .subscribe(posts => {
        this._posts.set(posts);
        this._loading.set(false);
      });
  }

  // ── GET single post ────────────────────────────────────────
  getPost(id: number) {
    return this.http.get<Post>(`${this.BASE}/posts/${id}`);
    // Returns Observable<Post> — caller subscribes
  }

  // ── GET with query parameters: /posts?userId=1&_limit=10 ──
  getPostsByUser(userId: number, limit = 10) {
    const params = new HttpParams()
      .set('userId', userId)
      .set('_limit', limit);

    return this.http.get<Post[]>(`${this.BASE}/posts`, { params });
  }
}

import { Component, inject, OnInit } from '@angular/core';
import { PostsService } from './posts.service';

@Component({
  selector: 'app-posts-page',
  standalone: true,
  template: `
    <h1>Posts ({{ postsService.count() }})</h1>

    @if (postsService.loading()) {
      <!-- Loading skeleton -->
      <div class="skeleton" *ngFor="let i of [1,2,3]">Loading...</div>

    } @else if (postsService.error()) {
      <div class="error-banner">
        ⚠️ {{ postsService.error() }}
        <button (click)="postsService.loadPosts()">Retry</button>
      </div>

    } @else {
      @for (post of postsService.posts(); track post.id) {
        <article>
          <h2>{{ post.title }}</h2>
          <p>{{ post.body }}</p>
        </article>
      } @empty {
        <p>No posts yet. <button (click)="postsService.loadPosts()">Load posts</button></p>
      }
    }
  `,
})
export class PostsPageComponent implements OnInit {
  postsService = inject(PostsService);

  ngOnInit(): void {
    this.postsService.loadPosts();
  }
}

import { Injectable, inject, signal } from '@angular/core';
import { HttpClient }  from '@angular/common/http';
import { Observable }  from 'rxjs';
import { tap }         from 'rxjs/operators';

export interface CreatePostDto { title: string; body: string; userId: number; }
export interface UpdatePostDto { title?: string; body?: string; }

@Injectable({ providedIn: 'root' })
export class PostsMutationService {
  private http = inject(HttpClient);
  private BASE  = 'https://jsonplaceholder.typicode.com';

  saving  = signal(false);
  deleting = signal(false);

  // ── POST — create a new resource ──────────────────────────
  createPost(dto: CreatePostDto): Observable<Post> {
    return this.http
      .post<Post>(`${this.BASE}/posts`, dto);
      // Angular serialises dto to JSON automatically
      // Content-Type: application/json is set automatically
  }

  // ── PUT — replace the full resource ───────────────────────
  replacePost(id: number, post: CreatePostDto): Observable<Post> {
    return this.http.put<Post>(`${this.BASE}/posts/${id}`, post);
  }

  // ── PATCH — update specific fields only ───────────────────
  updatePost(id: number, changes: UpdatePostDto): Observable<Post> {
    return this.http.patch<Post>(`${this.BASE}/posts/${id}`, changes);
  }

  // ── DELETE — remove a resource ────────────────────────────
  deletePost(id: number): Observable<void> {
    this.deleting.set(true);
    return this.http
      .delete<void>(`${this.BASE}/posts/${id}`)
      .pipe(tap(() => this.deleting.set(false)));
  }
}

