import { Injectable, inject } from '@angular/core';
import { HttpClient, HttpHeaders, HttpParams } from '@angular/common/http';

@Injectable({ providedIn: 'root' })
export class ApiService {
  private http = inject(HttpClient);

  // ── Custom headers ────────────────────────────────────────
  getWithAuth(token: string) {
    const headers = new HttpHeaders({
      'Authorization': `Bearer ${token}`,
      'X-Api-Version': '2',
    });

    return this.http.get<Data[]>('/api/data', { headers });
  }

  // ── HttpHeaders is immutable — chain .set() calls ─────────
  postWithHeaders(body: object) {
    const headers = new HttpHeaders()
      .set('Content-Type', 'application/json')
      .set('Accept-Language', 'en-US');

    return this.http.post<Response>('/api/items', body, { headers });
  }

  // ── Query parameters: /products?category=books&page=2 ─────
  searchProducts(category: string, page: number) {
    const params = new HttpParams()
      .set('category', category)
      .set('page', page)
      .set('limit', 20);

    return this.http.get<Product[]>('/api/products', { params });
  }

  // ── observe: 'response' — access status code and headers ──
  getFullResponse() {
    return this.http.get<User>('/api/me', { observe: 'response' });
    // Returns Observable<HttpResponse<User>>
    // response.status, response.headers, response.body available
  }

  // ── responseType: 'blob' — download a file ────────────────
  downloadFile(fileId: string) {
    return this.http.get(`/api/files/${fileId}`, {
      responseType: 'blob',              // don't parse as JSON
      observe: 'response',               // get headers too (filename)
    });
  }
}

import { Injectable, inject, signal } from '@angular/core';
import {
  HttpClient, HttpErrorResponse
} from '@angular/common/http';
import {
  catchError, retry, throwError, EMPTY, of, timer
} from 'rxjs';
import { switchMap } from 'rxjs/operators';

@Injectable({ providedIn: 'root' })
export class ResilientApiService {
  private http = inject(HttpClient);

  // ── Pattern 1: catch, set error signal, return EMPTY ──────
  loadData = () => {
    const error = signal<string | null>(null);

    const data$ = this.http.get<Item[]>('/api/items').pipe(
      catchError((err: HttpErrorResponse) => {
        error.set(this.friendlyMessage(err));
        return EMPTY;
      })
    );
    return { data$, error };
  };

  // ── Pattern 2: auto-retry on failure (network errors) ─────
  loadWithRetry() {
    return this.http.get<Data>('/api/data').pipe(
      retry({ count: 3, delay: 1000 }),  // retry 3× with 1s delay
      catchError(err => throwError(() => err))  // propagate after retries
    );
  }

  // ── Pattern 3: exponential backoff ────────────────────────
  loadWithBackoff() {
    return this.http.get<Data>('/api/data').pipe(
      retry({
        count: 4,
        delay: (error, attempt) => timer(Math.pow(2, attempt) * 500)
        //  attempt 1: 500ms, 2: 1000ms, 3: 2000ms, 4: 4000ms
      })
    );
  }

  // ── Map HttpErrorResponse to a user-friendly message ──────
  private friendlyMessage(err: HttpErrorResponse): string {
    if (err.status === 0) {
      return 'No internet connection. Please check your network.';
    }
    if (err.status === 401) return 'You are not logged in.';
    if (err.status === 403) return 'You do not have permission.';
    if (err.status === 404) return 'The requested resource was not found.';
    if (err.status >= 500) return 'Server error. Please try again later.';
    return err.message ?? 'An unexpected error occurred.';
  }
}

import { HttpInterceptorFn, HttpRequest, HttpHandlerFn } from '@angular/common/http';
import { inject } from '@angular/core';
import { AuthService } from '../services/auth.service';

// Functional interceptor — no class, just a function
export const authInterceptor: HttpInterceptorFn = (
  req: HttpRequest<unknown>,
  next: HttpHandlerFn
) => {
  const auth  = inject(AuthService);
  const token = auth.getToken();

  // Don't add auth header to public endpoints
  if (!token || req.url.includes('/public/')) {
    return next(req);   // pass through unchanged
  }

  // HttpRequest is immutable — clone to modify
  const authReq = req.clone({
    setHeaders: {
      Authorization: `Bearer ${token}`,
      'X-Request-Id': crypto.randomUUID(),
    }
  });

  return next(authReq);   // pass the modified request
};

import { HttpInterceptorFn }  from '@angular/common/http';
import { tap, finalize }      from 'rxjs/operators';

export const loggingInterceptor: HttpInterceptorFn = (req, next) => {
  const started = Date.now();

  console.log(`→ ${req.method} ${req.url}`);

  return next(req).pipe(
    tap({
      // Response arrived
      next:  event  => console.log(`← 200 ${req.url}`),
      error: err    => console.error(`✗ ${err.status} ${req.url}`, err.message),
    }),
    finalize(() => {
      const elapsed = Date.now() - started;
      console.log(`⏱ ${req.method} ${req.url} — ${elapsed}ms`);
    })
  );
};

// ── Error + Redirect Interceptor ──────────────────────────
import { inject }         from '@angular/core';
import { Router }         from '@angular/router';
import { catchError }     from 'rxjs';
import { throwError }     from 'rxjs';

export const errorInterceptor: HttpInterceptorFn = (req, next) => {
  const router = inject(Router);

  return next(req).pipe(
    catchError(err => {
      if (err.status === 401) {
        // Token expired or invalid — redirect to login globally
        router.navigate(['/login'], { queryParams: { returnUrl: router.url } });
      }
      if (err.status === 403) {
        router.navigate(['/forbidden']);
      }
      return throwError(() => err);  // still propagate to the service
    })
  );
};

import { Injectable, inject } from '@angular/core';
import { HttpClient } from '@angular/common/http';
import { forkJoin, switchMap, map, shareReplay } from 'rxjs';

@Injectable({ providedIn: 'root' })
export class AdvancedHttpService {
  private http = inject(HttpClient);
  private BASE  = 'https://jsonplaceholder.typicode.com';

  // ── Parallel requests — wait for all ──────────────────────
  // forkJoin fires all requests at once; result array matches input order
  loadDashboard() {
    return forkJoin({
      users:  this.http.get<User[]>(`${this.BASE}/users`),
      posts:  this.http.get<Post[]>(`${this.BASE}/posts`),
      albums: this.http.get<Album[]>(`${this.BASE}/albums`),
    });
    // Returns: Observable<{ users: User[]; posts: Post[]; albums: Album[] }>
    // All 3 requests fire simultaneously — completes when ALL succeed
  }

  // ── Chain requests — result of first feeds the second ─────
  // switchMap cancels the previous inner request on each new outer value
  loadUserWithPosts(userId$: Observable<number>) {
    return userId$.pipe(
      switchMap(id =>
        this.http.get<User>(`${this.BASE}/users/${id}`).pipe(
          switchMap(user =>
            this.http.get<Post[]>(`${this.BASE}/posts?userId=${user.id}`).pipe(
              map(posts => ({ user, posts }))  // combine both results
            )
          )
        )
      )
    );
  }

  // ── Cache a request — share one response to all subscribers
  private config$ = this.http.get<AppConfig>('/api/config').pipe(
    shareReplay(1)   // cache the last emission, replay to new subscribers
  );

  getConfig() {
    return this.config$;  // second+ subscriber gets the cached response
  }

  // ── Transform the response shape ──────────────────────────
  getUserNames() {
    return this.http.get<User[]>(`${this.BASE}/users`).pipe(
      map(users => users.map(u => ({ id: u.id, label: u.name })))
    );
  }
}

import { Injectable, inject, signal, computed } from '@angular/core';
import { HttpClient } from '@angular/common/http';
import { catchError, EMPTY, tap } from 'rxjs';

interface Todo { id: number; title: string; completed: boolean; }
interface CreateTodoDto { title: string; userId: number; }

@Injectable({ providedIn: 'root' })
export class TodosService {
  private http  = inject(HttpClient);
  private BASE   = 'https://jsonplaceholder.typicode.com/todos';

  private _todos   = signal<Todo[]>([]);
  private _loading = signal(false);
  private _error   = signal<string | null>(null);
  private _saving  = signal(false);

  readonly todos      = this._todos.asReadonly();
  readonly loading    = this._loading.asReadonly();
  readonly error      = this._error.asReadonly();
  readonly saving     = this._saving.asReadonly();
  readonly doneCount  = computed(() => this._todos().filter(t => t.completed).length);
  readonly totalCount = computed(() => this._todos().length);

  // ── READ ──────────────────────────────────────────────────
  load(): void {
    this._loading.set(true);
    this.http.get<Todo[]>(`${this.BASE}?_limit=10`).pipe(
      catchError(err => { this._error.set(err.message); this._loading.set(false); return EMPTY; })
    ).subscribe(todos => { this._todos.set(todos); this._loading.set(false); });
  }

  // ── CREATE ────────────────────────────────────────────────
  create(dto: CreateTodoDto): void {
    this._saving.set(true);
    this.http.post<Todo>(this.BASE, { ...dto, completed: false }).pipe(
      catchError(err => { this._error.set(err.message); this._saving.set(false); return EMPTY; })
    ).subscribe(todo => {
      this._todos.update(list => [todo, ...list]);  // optimistic prepend
      this._saving.set(false);
    });
  }

  // ── UPDATE ────────────────────────────────────────────────
  toggle(id: number): void {
    const todo = this._todos().find(t => t.id === id);
    if (!todo) return;
    // Optimistic update — update UI immediately, then sync with server
    this._todos.update(list => list.map(t => t.id === id ? { ...t, completed: !t.completed } : t));
    this.http.patch<Todo>(`${this.BASE}/${id}`, { completed: !todo.completed })
      .pipe(catchError(() => {
        // Revert on failure
        this._todos.update(list => list.map(t => t.id === id ? { ...t, completed: todo.completed } : t));
        return EMPTY;
      })).subscribe();
  }

  // ── DELETE ────────────────────────────────────────────────
  delete(id: number): void {
    this._todos.update(list => list.filter(t => t.id !== id));  // optimistic
    this.http.delete(`${this.BASE}/${id}`)
      .pipe(catchError(() => {
        this.load();   // revert by re-fetching
        return EMPTY;
      })).subscribe();
  }
}
